import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic3x3() {
        int[][] grid = {{1,2,3},{4,5,6},{7,8,9}};
        assertEquals(40L, new Solution().boundarySum(grid));
    }

    @Test
    void twoByTwo_allBoundary() {
        // 2×2: every cell is on the boundary
        int[][] grid = {{10,20},{30,40}};
        assertEquals(100L, new Solution().boundarySum(grid));
    }

    @Test
    void singleCell() {
        int[][] grid = {{7}};
        assertEquals(7L, new Solution().boundarySum(grid));
    }

    @Test
    void singleRow() {
        // Every cell in a single row is a boundary cell
        int[][] grid = {{1, 2, 3}};
        assertEquals(6L, new Solution().boundarySum(grid));
    }

    @Test
    void singleColumn() {
        // Every cell in a single column is a boundary cell
        int[][] grid = {{1},{2},{3}};
        assertEquals(6L, new Solution().boundarySum(grid));
    }

    @Test
    void emptyGrid() {
        int[][] grid = {};
        assertEquals(0L, new Solution().boundarySum(grid));
    }

    @Test
    void largeValuesNoOverflow() {
        // Values near Integer.MAX_VALUE; sum must use long arithmetic
        int max = Integer.MAX_VALUE; // 2_147_483_647
        int[][] grid = {
            {max, max, max},
            {max,   0, max},
            {max, max, max}
        };
        // 8 boundary cells, each max; interior 0 excluded
        long expected = 8L * max;
        assertEquals(expected, new Solution().boundarySum(grid));
    }
}
